import { impuestos } from "@/constants/impuestos";
import {
  cotizadorCatalogoRepository,
  type CotizadorCatalogoRepository,
} from "@/repositories/cotizador-catalogo.repository";
import {
  cotizacionesRepository,
  type CotizacionesRepository,
} from "@/repositories/cotizaciones-repository";
import type { CrearCotizacionInput } from "@/types/cotizacion";
import type {
  CotizadorCatalogoBase,
  CotizadorOpcionesItem,
  ConfigurationMaterial,
  LaborCost,
  LineGlassCompatibility,
  Material,
  ProductType,
  SystemConfiguration,
  SystemLine,
} from "@/types/cotizador";
import type { EntityId } from "@/types/common";
import type {
  CrearCotizacionItemBreakdownInput,
  CrearCotizacionItemInput,
} from "@/types/cotizacion-item";

type CotizadorServiceDeps = {
  catalogoRepository?: CotizadorCatalogoRepository;
  cotizacionesRepository?: CotizacionesRepository;
};

export type CalcularItemConfiguradoInput = {
  organizationId: EntityId;
  productTypeId: EntityId;
  systemLineId: EntityId;
  configurationId: EntityId;
  glassMaterialId?: EntityId | null;
  cantidad: number;
  ancho: number;
  alto: number;
  color?: string | null;
  nombre?: string | null;
  descripcion?: string | null;
  observaciones?: string | null;
  margenPct?: number | null;
  incluirManoDeObra?: boolean;
};

export type CalcularCotizacionInput = {
  organizationId: EntityId;
  proyectoId?: EntityId | null;
  numero?: string | null;
  estado?: string;
  descuentoPct?: number | null;
  flete?: number | null;
  notas?: string | null;
  validoHasta?: string | null;
  estadoComercial?: string | null;
  items: CalcularItemConfiguradoInput[];
};

export type CargarOpcionesItemInput = {
  organizationId: EntityId;
  productTypeId: EntityId;
  systemLineId: EntityId;
};

type FormulaContext = Record<string, number>;

const DEFAULT_FLETE = 0;
const DEFAULT_MARGEN_PCT = 35;

function idsAreEqual(left: EntityId | null | undefined, right: EntityId | null | undefined) {
  if (left === null || left === undefined || right === null || right === undefined) {
    return false;
  }

  return String(left) === String(right);
}

function round(value: number, digits = 2) {
  const multiplier = 10 ** digits;

  return Math.round(value * multiplier) / multiplier;
}

function assertPositive(value: number, label: string) {
  if (!Number.isFinite(value) || value <= 0) {
    throw new Error(`${label} debe ser mayor a cero`);
  }
}

function normalizeMargin(margenPct: number | null | undefined) {
  if (margenPct === null || margenPct === undefined) {
    return DEFAULT_MARGEN_PCT;
  }

  if (!Number.isFinite(margenPct) || margenPct < 0) {
    throw new Error("El margen no puede ser negativo");
  }

  return margenPct;
}

function calculateAreaM2(anchoMm: number, altoMm: number) {
  assertPositive(anchoMm, "El ancho");
  assertPositive(altoMm, "El alto");

  return round((anchoMm / 1000) * (altoMm / 1000), 4);
}

function isGlassRole(rolMaterial: string | null) {
  const normalized = rolMaterial?.trim().toLowerCase();

  return normalized === "vidrio" || normalized === "glass";
}

function buildFormulaContext(input: {
  anchoMm: number;
  altoMm: number;
  areaM2: number;
  cantidad: number;
  hojas: number;
}) {
  return {
    ANCHO: input.anchoMm,
    ALTO: input.altoMm,
    ANCHO_MM: input.anchoMm,
    ALTO_MM: input.altoMm,
    ANCHO_M: input.anchoMm / 1000,
    ALTO_M: input.altoMm / 1000,
    AREA_M2: input.areaM2,
    CANTIDAD: input.cantidad,
    HOJAS: input.hojas,
  } satisfies FormulaContext;
}

function evaluateFormula(formula: string | null, context: FormulaContext) {
  if (!formula || !formula.trim()) {
    return 1;
  }

  const expression = formula.replace(
    /\b[A-Za-z_][A-Za-z0-9_]*\b/g,
    (token) => {
      const value = context[token.toUpperCase()];

      if (value === undefined) {
        throw new Error(`Variable de formula no soportada: ${token}`);
      }

      return String(value);
    }
  );

  if (!/^[0-9+\-*/().\s]+$/.test(expression)) {
    throw new Error("La formula contiene caracteres no permitidos");
  }

  const result = Function(`"use strict"; return (${expression});`)();

  if (typeof result !== "number" || Number.isNaN(result) || !Number.isFinite(result)) {
    throw new Error("La formula no produjo un numero valido");
  }

  return result;
}

function resolveLaborQuantity(
  laborCost: LaborCost,
  context: FormulaContext,
  cantidadItems: number
) {
  const unidad = laborCost.unidad?.trim().toLowerCase() ?? "unit";

  switch (unidad) {
    case "m2":
      return context.AREA_M2 * cantidadItems;
    case "hoja":
    case "hojas":
      return context.HOJAS * cantidadItems;
    case "unit":
    case "item":
    case "unidad":
    default:
      return cantidadItems;
  }
}

function resolveGlassMaterialId(
  input: CalcularItemConfiguradoInput,
  compatibilities: LineGlassCompatibility[]
) {
  if (input.glassMaterialId) {
    if (compatibilities.length === 0) {
      return input.glassMaterialId;
    }

    const match = compatibilities.find((entry) =>
      idsAreEqual(entry.glassMaterialId, input.glassMaterialId)
    );

    if (!match || !match.permitido) {
      throw new Error("El vidrio seleccionado no es compatible con la linea");
    }

    return input.glassMaterialId;
  }

  if (compatibilities.length === 0) {
    return null;
  }

  const recommended = compatibilities.find(
    (entry) => entry.permitido && entry.recomendado
  );

  if (recommended) {
    return recommended.glassMaterialId;
  }

  return compatibilities.find((entry) => entry.permitido)?.glassMaterialId ?? null;
}

function resolveMaterialForConfiguration(
  entry: ConfigurationMaterial,
  resolvedGlassMaterialId: EntityId | null
) {
  if (isGlassRole(entry.rolMaterial) && resolvedGlassMaterialId !== null) {
    return resolvedGlassMaterialId;
  }

  return entry.materialId;
}

function calculateBreakdownPrice(costoTotal: number, margenPct: number) {
  return round(costoTotal * (1 + margenPct / 100), 2);
}

function buildConfiguredBreakdownEntries(input: {
  configurationMaterials: ConfigurationMaterial[];
  materialsById: Map<string, Material>;
  laborCosts: LaborCost[];
  configuration: SystemConfiguration;
  resolvedGlassMaterialId: EntityId | null;
  marginPct: number;
  context: FormulaContext;
  cantidadItems: number;
}) {
  const breakdown: CrearCotizacionItemBreakdownInput[] = [];

  for (const entry of input.configurationMaterials) {
    const materialId = resolveMaterialForConfiguration(
      entry,
      input.resolvedGlassMaterialId
    );
    const material = input.materialsById.get(String(materialId));

    if (!material) {
      throw new Error(
        `No se encontro el material ${materialId} para la configuracion seleccionada`
      );
    }

    const formulaValue = evaluateFormula(entry.formula, input.context);

    if (formulaValue < 0) {
      throw new Error("La formula del material no puede generar cantidades negativas");
    }

    const cantidadBase = formulaValue * input.cantidadItems;
    const cantidadConMerma = round(
      cantidadBase * (1 + entry.mermaPct / 100),
      4
    );

    if (cantidadConMerma === 0 && !entry.requerido) {
      continue;
    }

    const costoTotal = round(cantidadConMerma * material.costo, 2);
    const precioTotal = calculateBreakdownPrice(costoTotal, input.marginPct);

    breakdown.push({
      materialId: material.id,
      descripcion: material.nombre,
      unidad: material.unidad,
      cantidad: cantidadConMerma,
      costoUnitario: material.costo,
      costoTotal,
      precioUnitario: round(
        cantidadConMerma === 0 ? 0 : precioTotal / cantidadConMerma,
        4
      ),
      precioTotal,
      origen: "material",
    });
  }

  for (const laborCost of input.laborCosts) {
    const cantidad = round(
      resolveLaborQuantity(laborCost, input.context, input.cantidadItems),
      4
    );

    if (cantidad <= 0) {
      continue;
    }

    const costoTotal = round(cantidad * laborCost.monto, 2);
    const precioTotal = calculateBreakdownPrice(costoTotal, input.marginPct);

    breakdown.push({
      descripcion: laborCost.nombre ?? "Mano de obra",
      unidad: laborCost.unidad,
      cantidad,
      costoUnitario: laborCost.monto,
      costoTotal,
      precioUnitario: round(cantidad === 0 ? 0 : precioTotal / cantidad, 4),
      precioTotal,
      origen: "mano_obra",
    });
  }

  if (breakdown.length === 0) {
    throw new Error("La configuracion seleccionada no genero desglose de costos");
  }

  return breakdown;
}

function resolveCatalogReferences(input: {
  systemLines: SystemLine[];
  productTypes: ProductType[];
  configuration: SystemConfiguration;
  productTypeId: EntityId;
  systemLineId: EntityId;
}) {
  const line = input.systemLines.find((entry) =>
    idsAreEqual(entry.id, input.systemLineId)
  );
  const productType = input.productTypes.find((entry) =>
    idsAreEqual(entry.id, input.productTypeId)
  );

  return {
    line,
    productType,
  };
}

export function createCotizadorService(deps: CotizadorServiceDeps = {}) {
  const catalogoRepository =
    deps.catalogoRepository ?? cotizadorCatalogoRepository;
  const repository = deps.cotizacionesRepository ?? cotizacionesRepository;

  async function cargarCatalogoBase(
    organizationId: EntityId
  ): Promise<CotizadorCatalogoBase> {
    const [productTypes, systemLines, materials] = await Promise.all([
      catalogoRepository.listProductTypes(),
      catalogoRepository.listSystemLinesByOrganizationId(organizationId),
      catalogoRepository.listMaterialsByOrganizationId(organizationId),
    ]);

    return {
      productTypes,
      systemLines,
      materials,
    };
  }

  async function cargarOpcionesItem(
    input: CargarOpcionesItemInput
  ): Promise<CotizadorOpcionesItem> {
    const [configuraciones, compatibilities, materials] = await Promise.all([
      catalogoRepository.listConfigurations({
        organizationId: input.organizationId,
        productTypeId: input.productTypeId,
        systemLineId: input.systemLineId,
      }),
      catalogoRepository.listCompatibleGlassBySystemLineId(input.systemLineId),
      catalogoRepository.listMaterialsByOrganizationId(input.organizationId),
    ]);

    const materialesCompatibles = new Map(
      materials.map((material) => [String(material.id), material] as const)
    );

    return {
      configuraciones,
      vidriosCompatibles: compatibilities
        .filter((entry) => entry.permitido)
        .map((entry) => materialesCompatibles.get(String(entry.glassMaterialId)))
        .filter((entry): entry is Material => Boolean(entry)),
    };
  }

  async function calcularItemConfigurado(
    input: CalcularItemConfiguradoInput
  ): Promise<CrearCotizacionItemInput> {
    assertPositive(input.cantidad, "La cantidad");
    const marginPct = normalizeMargin(input.margenPct);
    const areaM2 = calculateAreaM2(input.ancho, input.alto);

    const [
      productTypes,
      systemLines,
      configurations,
      configurationMaterials,
      compatibilities,
      materials,
      laborCosts,
    ] = await Promise.all([
      catalogoRepository.listProductTypes(),
      catalogoRepository.listSystemLinesByOrganizationId(input.organizationId),
      catalogoRepository.listConfigurations({
        organizationId: input.organizationId,
        productTypeId: input.productTypeId,
        systemLineId: input.systemLineId,
      }),
      catalogoRepository.listConfigurationMaterials(input.configurationId),
      catalogoRepository.listCompatibleGlassBySystemLineId(input.systemLineId),
      catalogoRepository.listMaterialsByOrganizationId(input.organizationId),
      input.incluirManoDeObra === false
        ? Promise.resolve([])
        : catalogoRepository.listActiveLaborCostsByOrganizationId(
            input.organizationId
          ),
    ]);

    const configuration = configurations.find((entry) =>
      idsAreEqual(entry.id, input.configurationId)
    );

    if (!configuration) {
      throw new Error("La configuracion seleccionada no existe o no esta activa");
    }

    if (configurationMaterials.length === 0) {
      throw new Error("La configuracion seleccionada no tiene materiales asociados");
    }

    const resolvedGlassMaterialId = resolveGlassMaterialId(input, compatibilities);
    const { line, productType } = resolveCatalogReferences({
      systemLines,
      productTypes,
      configuration,
      productTypeId: input.productTypeId,
      systemLineId: input.systemLineId,
    });

    if (!line) {
      throw new Error("La linea del sistema no existe para esta organizacion");
    }

    const materialsById = new Map(
      materials.map((material) => [String(material.id), material] as const)
    );
    const resolvedGlass = resolvedGlassMaterialId
      ? materialsById.get(String(resolvedGlassMaterialId)) ?? null
      : null;
    const formulaContext = buildFormulaContext({
      anchoMm: input.ancho,
      altoMm: input.alto,
      areaM2,
      cantidad: input.cantidad,
      hojas: configuration.hojas ?? 1,
    });

    const breakdown = buildConfiguredBreakdownEntries({
      configurationMaterials,
      materialsById,
      laborCosts,
      configuration,
      resolvedGlassMaterialId,
      marginPct,
      context: formulaContext,
      cantidadItems: input.cantidad,
    });

    const costoTotal = round(
      breakdown.reduce((accumulator, entry) => accumulator + entry.costoTotal, 0),
      2
    );
    const subtotal = round(
      breakdown.reduce((accumulator, entry) => accumulator + entry.precioTotal, 0),
      2
    );
    const costoUnitario = round(costoTotal / input.cantidad, 2);
    const precioUnitario = round(subtotal / input.cantidad, 2);
    const utilidad = round(subtotal - costoTotal, 2);
    const margenCalculado =
      costoTotal === 0 ? marginPct : round((utilidad / costoTotal) * 100, 2);

    return {
      cantidad: input.cantidad,
      precioUnitario,
      subtotal,
      organizationId: input.organizationId,
      ancho: input.ancho,
      alto: input.alto,
      areaM2,
      linea: line.nombre,
      color: input.color ?? null,
      vidrio: resolvedGlass?.nombre ?? null,
      nombre:
        input.nombre ??
        configuration.nombre ??
        productType?.nombre ??
        "Item configurable",
      descripcion:
        input.descripcion ??
        `${productType?.nombre ?? "Producto"} ${configuration.nombre ?? ""}`.trim(),
      observaciones: input.observaciones ?? null,
      unidad: "unit",
      tipoItem: "configurado",
      productTypeId: input.productTypeId,
      systemLineId: input.systemLineId,
      configurationId: input.configurationId,
      costoUnitario,
      costoTotal,
      margenPct: margenCalculado,
      utilidad,
      breakdown,
    };
  }

  async function calcularCotizacion(
    input: CalcularCotizacionInput
  ): Promise<CrearCotizacionInput> {
    if (input.items.length === 0) {
      throw new Error("La cotizacion debe tener al menos un item");
    }

    const descuentoPct = input.descuentoPct ?? 0;

    if (descuentoPct < 0) {
      throw new Error("El descuento no puede ser negativo");
    }

    const calculatedItems = await Promise.all(
      input.items.map((item) => calcularItemConfigurado(item))
    );
    const subtotalBruto = round(
      calculatedItems.reduce((accumulator, item) => accumulator + item.subtotal, 0),
      2
    );
    const descuentoValor = round(subtotalBruto * (descuentoPct / 100), 2);
    const subtotalNeto = round(subtotalBruto - descuentoValor, 2);
    const flete = input.flete ?? DEFAULT_FLETE;
    const iva = round(subtotalNeto * impuestos.iva, 2);
    const total = round(subtotalNeto + iva + flete, 2);
    const costoTotal = round(
      calculatedItems.reduce(
        (accumulator, item) => accumulator + (item.costoTotal ?? 0),
        0
      ),
      2
    );
    const utilidadTotal = round(subtotalNeto + flete - costoTotal, 2);
    const margenPct =
      costoTotal === 0 ? 0 : round((utilidadTotal / costoTotal) * 100, 2);

    return {
      proyectoId: input.proyectoId ?? null,
      organizationId: input.organizationId,
      numero: input.numero ?? null,
      estado: input.estado ?? "borrador",
      descuentoPct,
      flete,
      iva,
      notas: input.notas ?? null,
      validoHasta: input.validoHasta ?? null,
      subtotalNeto,
      costoTotal,
      margenPct,
      utilidadTotal,
      estadoComercial: input.estadoComercial ?? null,
      items: calculatedItems,
      total,
    };
  }

  async function crearCotizacion(input: CalcularCotizacionInput) {
    const cotizacion = await calcularCotizacion(input);

    return repository.create(cotizacion);
  }

  return {
    cargarCatalogoBase,
    cargarOpcionesItem,
    calcularItemConfigurado,
    calcularCotizacion,
    crearCotizacion,
  };
}

export const cotizadorService = createCotizadorService();
